import React from "react";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

function ModelAccuracy() {

  // ✅ Only 2 models (your requirement)
  const modelData = {
    labels: ["Random Forest", "XGBoost"],
    datasets: [
      {
        label: "Accuracy %",
        data: [91.2, 93.4],
        backgroundColor: ["#3b82f6", "#22c55e"]
      }
    ]
  };

  return (
    <div style={{ width: "80%", margin: "50px auto", textAlign: "center" }}>
      
      <h2>Model Comparison</h2>

      {/* ✅ Graph */}
      <Bar data={modelData} />

      {/* ✅ Training & Testing Info */}
      <div style={{ marginTop: "30px" }}>
        <p><strong>Training Data:</strong> 80%</p>
        <p><strong>Testing Data:</strong> 20%</p>
      </div>

    </div>
  );
}

export default ModelAccuracy;
